// Etape 1 : fenetre de scan
const now = new Date();
const windowEnd = now.toISOString();
const windowStart = new Date(now.getTime() - 65 * 60 * 1000).toISOString();
const pad = (n) => String(n).padStart(2, '0');
const scanTraceId = `sentinel-scan-${now.getUTCFullYear()}${pad(now.getUTCMonth()+1)}${pad(now.getUTCDate())}${pad(now.getUTCHours())}`;
return [{ json: { window_start: windowStart, window_end: windowEnd, scan_trace_id: scanTraceId } }];

// Etapes 3-5 : detection RULE 1 (MCP_NO_LOG), RULE 2 (REFUSAL_BURST), RULE 3 (AGENT_SILENT)
// Entree : items = pages AGENTS_LOG de la fenetre

const items = $input.all();
const meta = $('Compute scan window').item.json;
const windowStartMs = new Date(meta.window_start).getTime();
const windowEndMs = new Date(meta.window_end).getTime();
const scanTraceId = meta.scan_trace_id;

// Normaliser en entrees simples
const logs = items.map(it => {
  const p = it.json.properties || {};
  return {
    agent: p.agent?.select?.name || null,
    scope: p.scope?.select?.name || null,
    statut: p.statut?.select?.name || null,
    timestamp: p.timestamp?.date?.start || null,
    trace_id: p.trace_id?.rich_text?.[0]?.plain_text || null,
    action: p.action?.title?.[0]?.plain_text || null
  };
});

const alerts = [];

// --- RULE 1 : MCP_NO_LOG ---
// Hypothese : la liste des actions MCP externes (n8n, vercel, supabase audit) est remontee
// par des HTTP requests upstream. En MVP, on compare le compteur d'actions MCP observees
// (fourni par $('Fetch MCP sources')) au nombre d'entrees AGENTS_LOG sur la fenetre.
// Si ecart > 0, on leve une alerte CRITIQUE par evenement non-logue.
// TODO : cabler Fetch MCP sources (Vercel deployments, Supabase audit, n8n executions)
//        puis renseigner ici la logique de matching temporel +/- 5 min.

// --- RULE 2 : REFUSAL_BURST (HAUTE) ---
const refusalByAgent = {};
for (const l of logs) {
  if (l.scope === 'policy-refusal') {
    refusalByAgent[l.agent] = (refusalByAgent[l.agent] || 0) + 1;
  }
}
for (const [agent, count] of Object.entries(refusalByAgent)) {
  if (count >= 3) {
    alerts.push({
      niveau: 'HAUTE',
      regle_violee: 'REFUSAL_BURST',
      agent,
      mcp_source: 'none',
      detail: `Agent ${agent} a refuse ${count} fois en <= 65 min (fenetre ${meta.window_start})`,
      scan_trace_id: scanTraceId,
      action_ceo: 'Soit regles trop strictes, soit attaque en cours, investiguer.',
      timestamp: meta.window_end
    });
  }
}

// --- RULE 3 : AGENT_SILENT (MOYENNE) ---
// Agent cite dans git log recent ou n8n executions mais absent d'AGENTS_LOG.
// TODO : cabler source git/n8n executions pour activer. Placeholder ici.

// --- Comptage ---
const counts = { CRITIQUE: 0, HAUTE: 0, MOYENNE: 0, INFO: 0 };
for (const a of alerts) counts[a.niveau]++;

return [{ json: { alerts, counts, scan_trace_id: scanTraceId, meta, entries_scanned: logs.length } }];

// Emet une alerte par element. Execute apres Self-log pour ne pas interrompre si write fail.
const alerts = $('Detect rules 1-3').item.json.alerts || [];
return alerts.map(a => ({ json: a }));

